import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCase() {
        // 1 appears 3x, 2 appears 2x, 3 appears 1x => top-2: [1,2]
        int[] nums = {1, 1, 1, 2, 2, 3};
        assertArrayEquals(new int[]{1, 2}, new Solution().topKFrequent(nums, 2));
    }

    @Test
    void tiebreakByValueDescending() {
        // 5 and 3 both appear 2x; tiebreak desc value => [5,3]; 7 appears 1x excluded
        int[] nums = {5, 5, 3, 3, 7};
        assertArrayEquals(new int[]{5, 3}, new Solution().topKFrequent(nums, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // k=3 equals number of distinct values => return all three in order
        int[] nums = {4, 4, 2, 2, 9};
        assertArrayEquals(new int[]{4, 2, 9}, new Solution().topKFrequent(nums, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 2 distinct values => return both
        int[] nums = {4, 4, 2, 2};
        assertArrayEquals(new int[]{4, 2}, new Solution().topKFrequent(nums, 5));
    }

    @Test
    void emptyInput() {
        assertArrayEquals(new int[]{}, new Solution().topKFrequent(new int[]{}, 3));
    }

    @Test
    void allSameFrequency() {
        // 10, 20, 30 each appear once; tiebreak desc value => [30,20,10]; top-2: [30,20]
        int[] nums = {10, 20, 30};
        assertArrayEquals(new int[]{30, 20}, new Solution().topKFrequent(nums, 2));
    }

    @Test
    void singleElement() {
        int[] nums = {7};
        assertArrayEquals(new int[]{7}, new Solution().topKFrequent(nums, 1));
    }
}
